#include<bits/stdc++.h>
using namespace std;
int main(){
	int sum=0,wz=-1;
	string a,b;
	getline(cin,b);
	for(int i=0;i<b.size();i++){
		if(b[i]<='Z'&&b[i]>='A'){
			b[i]+='a'-'A';
		}
	}//单词转小写 
	getline(cin,a);
	string dc="";
	for(int i=0;i<a.size();i++){
		if(a[i]<='Z'&&a[i]>='A'){
			a[i]+='a'-'A';
		}//句子转小写 
		if(a[i]!=' '){
			dc+=a[i];
		}//加入dc 
		else{
			if(dc==b){
				sum++;
				if(wz==-1){
					wz=i-dc.size();
				}
			}
			dc="";
		}
	}
	if(dc==b){
		sum++;
		if(wz==-1){
			wz=a.size()-dc.size();
		}
	}
	if(sum){
		cout<<sum<<" "<<wz;
	}
	else{
		cout<<-1;
	}
}
